import{_ as n,c as a,o as e,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"命令: 监控与修剪 | opencode-dynamic-context-pruning","description":"学习使用 DCP 的 4 个命令监控和手动修剪。教你 /dcp context 查看会话，/dcp stats 查看统计，/dcp sweep 手动触发修剪。","frontmatter":{"title":"命令: 监控与修剪 | opencode-dynamic-context-pruning","sidebarTitle":"监控 Token、手动修剪","subtitle":"DCP 命令使用指南：监控与手动修剪","description":"学习使用 DCP 的 4 个命令监控和手动修剪。教你 /dcp context 查看会话，/dcp stats 查看统计，/dcp sweep 手动触发修剪。","tags":["DCP 命令","Token 监控","手动修剪"],"prerequisite":["start-getting-started","platforms-auto-pruning"],"order":3},"headers":[],"relativePath":"zh/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md","filePath":"zh/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"}'),o={name:"zh/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"};function p(d,s,l,c,i,r){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="dcp-命令使用指南-监控与手动修剪" tabindex="-1">DCP 命令使用指南：监控与手动修剪 <a class="header-anchor" href="#dcp-命令使用指南-监控与手动修剪" aria-label="Permalink to &quot;DCP 命令使用指南：监控与手动修剪&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>使用 <code>/dcp context</code> 查看当前会话的 Token 使用分布</li><li>使用 <code>/dcp stats</code> 查看累计修剪统计</li><li>使用 <code>/dcp sweep [n]</code> 手动触发修剪</li><li>理解受保护工具和文件的保护机制</li><li>了解 Token 计算策略和节省效果</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>长对话中，Token 消耗越来越快，但你不知道：</p><ul><li>当前会话的 Token 都花在哪了？</li><li>DCP 究竟帮你省了多少？</li><li>怎么手动清理那些不再需要的工具输出？</li><li>哪些工具会被保护，不会被修剪？</li></ul><p>这些问题不搞清楚，你可能无法充分利用 DCP 的优化效果，甚至可能在关键时刻误删重要信息。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p>当你：</p><ul><li>想了解当前会话的 Token 构成</li><li>需要快速清理对话历史</li><li>想验证 DCP 的修剪效果</li><li>准备开始新的任务前做一次上下文清理</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>DCP 提供了 4 个 Slash 命令，帮助你监控和控制 Token 使用：</p><table tabindex="0"><thead><tr><th>命令</th><th>用途</th><th>适用场景</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>显示帮助</td><td>忘记命令时查看</td></tr><tr><td><code>/dcp context</code></td><td>分析当前会话 Token 分布</td><td>了解上下文构成</td></tr><tr><td><code>/dcp stats</code></td><td>查看累计修剪统计</td><td>验证长期效果</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>手动修剪工具</td><td>快速减少上下文大小</td></tr></tbody></table><p><strong>受保护机制</strong>：</p><p>所有修剪操作都会自动跳过：</p><ul><li><strong>受保护工具</strong>：<code>task</code>、<code>todowrite</code>、<code>todoread</code>、<code>discard</code>、<code>extract</code>、<code>batch</code>、<code>write</code>、<code>edit</code>、<code>plan_enter</code>、<code>plan_exit</code></li><li><strong>受保护文件</strong>：匹配配置中的 <code>protectedFilePatterns</code> 的文件路径</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>受保护工具和受保护文件的设置可以通过配置文件自定义。详见<a href="./../../start/configuration/">配置全解</a>。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-查看帮助信息" tabindex="-1">第 1 步：查看帮助信息 <a class="header-anchor" href="#第-1-步-查看帮助信息" aria-label="Permalink to &quot;第 1 步：查看帮助信息&quot;">​</a></h3><p>在 OpenCode 对话框中输入 <code>/dcp</code>。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><p><strong>检查点 ✅</strong>：确认看到了 3 个子命令的说明。</p><h3 id="第-2-步-分析当前会话-token-分布" tabindex="-1">第 2 步：分析当前会话 Token 分布 <a class="header-anchor" href="#第-2-步-分析当前会话-token-分布" aria-label="Permalink to &quot;第 2 步：分析当前会话 Token 分布&quot;">​</a></h3><p>输入 <code>/dcp context</code> 查看当前会话的 Token 使用情况。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                  DCP Context Analysis                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><p><strong>Token 分类说明</strong>：</p><table tabindex="0"><thead><tr><th>分类</th><th>计算方式</th><th>说明</th></tr></thead><tbody><tr><td><strong>System</strong></td><td><code>firstAssistant.input + cache.read - tokenizer(firstUserMessage)</code></td><td>系统提示词</td></tr><tr><td><strong>Tools</strong></td><td><code>tokenizer(toolInputs + toolOutputs) - prunedTokens</code></td><td>工具调用（已扣除修剪部分）</td></tr><tr><td><strong>User</strong></td><td><code>tokenizer(all user messages)</code></td><td>所有用户消息</td></tr><tr><td><strong>Assistant</strong></td><td><code>total - system - user - tools</code></td><td>AI 文本输出 + 推理 Token</td></tr></tbody></table><p><strong>检查点 ✅</strong>：确认看到了各分类的 Token 占比和数量。</p><h3 id="第-3-步-查看累计修剪统计" tabindex="-1">第 3 步：查看累计修剪统计 <a class="header-anchor" href="#第-3-步-查看累计修剪统计" aria-label="Permalink to &quot;第 3 步：查看累计修剪统计&quot;">​</a></h3><p>输入 <code>/dcp stats</code> 查看历史累计的修剪效果。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                    DCP Statistics                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens pruned: ~15.2K</span></span>
<span class="line"><span>  Tools pruned:   12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All-time:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens saved:  ~284.5K</span></span>
<span class="line"><span>  Tools pruned:   156</span></span>
<span class="line"><span>  Sessions:       8</span></span></code></pre></div><p><strong>统计说明</strong>：</p><ul><li><strong>Session</strong>：当前会话的修剪数据（内存中）</li><li><strong>All-time</strong>：所有历史会话的累计数据（磁盘持久化）</li></ul><p><strong>检查点 ✅</strong>：确认看到了当前会话和历史累计的修剪统计。</p><h3 id="第-4-步-手动修剪工具" tabindex="-1">第 4 步：手动修剪工具 <a class="header-anchor" href="#第-4-步-手动修剪工具" aria-label="Permalink to &quot;第 4 步：手动修剪工具&quot;">​</a></h3><p>有两种方式使用 <code>/dcp sweep</code>：</p><h4 id="方式一-修剪上一条用户消息后的所有工具" tabindex="-1">方式一：修剪上一条用户消息后的所有工具 <a class="header-anchor" href="#方式一-修剪上一条用户消息后的所有工具" aria-label="Permalink to &quot;方式一：修剪上一条用户消息后的所有工具&quot;">​</a></h4><p>输入 <code>/dcp sweep</code>（不带参数）。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept 8 tool(s) since previous user message.</span></span>
<span class="line"><span>Tokens saved: ~12,345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/config.ts</span></span>
<span class="line"><span>  • Read: src/utils.ts</span></span>
<span class="line"><span>  • Bash: npm test</span></span>
<span class="line"><span>  • Read: package.json</span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span></code></pre></div><h4 id="方式二-修剪最后-n-个工具" tabindex="-1">方式二：修剪最后 N 个工具 <a class="header-anchor" href="#方式二-修剪最后-n-个工具" aria-label="Permalink to &quot;方式二：修剪最后 N 个工具&quot;">​</a></h4><p>输入 <code>/dcp sweep 5</code> 修剪最后 5 个工具。</p><p><strong>你应该看到</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept last 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span>
<span class="line"><span>  • Bash: npm run build</span></span></code></pre></div><p><strong>受保护工具提示</strong>：</p><p>如果跳过了受保护工具，输出会显示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swept 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span>(2 protected tool(s) skipped)</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>受保护工具（如 <code>write</code>、<code>edit</code>）和受保护文件路径会被自动跳过，不会被修剪。</p></div><p><strong>检查点 ✅</strong>：确认看到了修剪的工具列表和节省的 Token 数量。</p><h3 id="第-5-步-再次查看修剪效果" tabindex="-1">第 5 步：再次查看修剪效果 <a class="header-anchor" href="#第-5-步-再次查看修剪效果" aria-label="Permalink to &quot;第 5 步：再次查看修剪效果&quot;">​</a></h3><p>修剪后，再次输入 <code>/dcp context</code> 查看新的 Token 分布。</p><p><strong>你应该看到</strong>：</p><ul><li><code>Tools</code> 分类占比下降</li><li><code>Summary</code> 中显示已修剪的工具数增加</li><li><code>Current context</code> 总数减少</li></ul><p><strong>检查点 ✅</strong>：确认 Token 使用量明显减少。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-错误-误删重要工具" tabindex="-1">❌ 错误：误删重要工具 <a class="header-anchor" href="#❌-错误-误删重要工具" aria-label="Permalink to &quot;❌ 错误：误删重要工具&quot;">​</a></h3><p><strong>场景</strong>：你刚用 <code>write</code> 工具写了一个关键文件，然后执行 <code>/dcp sweep</code>。</p><p><strong>错误结果</strong>：<code>write</code> 工具被修剪，AI 可能不知道文件已创建。</p><p><strong>正确做法</strong>：</p><ul><li><code>write</code>、<code>edit</code> 等工具默认受保护</li><li>不要手动修改 <code>protectedTools</code> 配置删除这些工具</li><li>关键任务完成后等待几个回合再清理</li></ul><h3 id="❌-错误-修剪时机不当" tabindex="-1">❌ 错误：修剪时机不当 <a class="header-anchor" href="#❌-错误-修剪时机不当" aria-label="Permalink to &quot;❌ 错误：修剪时机不当&quot;">​</a></h3><p><strong>场景</strong>：对话刚开始，只有几个工具调用就执行 <code>/dcp sweep</code>。</p><p><strong>错误结果</strong>：节省的 Token 很少，反而可能影响上下文连贯性。</p><p><strong>正确做法</strong>：</p><ul><li>等对话进行到一定程度（如 10+ 个工具调用）再清理</li><li>开始新任务前清理上一轮的工具输出</li><li>结合 <code>/dcp context</code> 判断是否值得清理</li></ul><h3 id="❌-错误-过度依赖手动修剪" tabindex="-1">❌ 错误：过度依赖手动修剪 <a class="header-anchor" href="#❌-错误-过度依赖手动修剪" aria-label="Permalink to &quot;❌ 错误：过度依赖手动修剪&quot;">​</a></h3><p><strong>场景</strong>：每次对话都手动执行 <code>/dcp sweep</code>。</p><p><strong>错误结果</strong>：</p><ul><li>自动修剪策略（去重、覆盖写入、清除错误）被浪费</li><li>增加操作负担</li></ul><p><strong>正确做法</strong>：</p><ul><li>默认开启自动修剪策略（配置：<code>strategies.*.enabled</code>）</li><li>手动修剪作为补充，在必要时使用</li><li>通过 <code>/dcp stats</code> 验证自动修剪效果</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>DCP 的 4 个命令帮助你监控和控制 Token 使用：</p><table tabindex="0"><thead><tr><th>命令</th><th>核心功能</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>显示帮助信息</td></tr><tr><td><code>/dcp context</code></td><td>分析当前会话 Token 分布</td></tr><tr><td><code>/dcp stats</code></td><td>查看累计修剪统计</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>手动修剪工具</td></tr></tbody></table><p><strong>Token 计算策略</strong>：</p><ul><li>System：系统提示词（从第一条响应推算）</li><li>Tools：工具输入输出（扣除修剪部分）</li><li>User：所有用户消息（估算）</li><li>Assistant：AI 输出 + 推理 Token（残差）</li></ul><p><strong>受保护机制</strong>：</p><ul><li>受保护工具：<code>task</code>、<code>todowrite</code>、<code>todoread</code>、<code>discard</code>、<code>extract</code>、<code>batch</code>、<code>write</code>、<code>edit</code>、<code>plan_enter</code>、<code>plan_exit</code></li><li>受保护文件：配置的 glob 模式</li><li>所有修剪操作自动跳过这些内容</li></ul><p><strong>最佳实践</strong>：</p><ul><li>定期查看 <code>/dcp context</code> 了解 Token 构成</li><li>新任务前执行 <code>/dcp sweep</code> 清理历史</li><li>依赖自动修剪，手动修剪作为补充</li><li>通过 <code>/dcp stats</code> 验证长期效果</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../advanced/protection/">保护机制</a></strong>。</p><p>你会学到：</p><ul><li>回合保护如何防止误修剪</li><li>如何自定义受保护工具列表</li><li>受保护文件模式的配置方法</li><li>子代理会话的特殊处理</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>/dcp 帮助命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>19-32</td></tr><tr><td>/dcp context 命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>238-247</td></tr><tr><td>Token 计算策略</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>5-38</td></tr><tr><td>/dcp stats 命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/stats.ts" target="_blank" rel="noreferrer"><code>lib/commands/stats.ts</code></a></td><td>46-67</td></tr><tr><td>/dcp sweep 命令</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/sweep.ts" target="_blank" rel="noreferrer"><code>lib/commands/sweep.ts</code></a></td><td>123-259</td></tr><tr><td>受保护工具配置</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>461</td></tr><tr><td>默认受保护工具列表</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>150-151</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>DEFAULT_PROTECTED_TOOLS</code>：默认受保护工具列表</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>handleHelpCommand()</code>：处理 /dcp 帮助命令</li><li><code>handleContextCommand()</code>：处理 /dcp context 命令</li><li><code>analyzeTokens()</code>：计算各类别的 Token 数量</li><li><code>handleStatsCommand()</code>：处理 /dcp stats 命令</li><li><code>handleSweepCommand()</code>：处理 /dcp sweep 命令</li><li><code>buildToolIdList()</code>：构建工具 ID 列表</li></ul></details>`,88)])])}const g=n(o,[["render",p]]);export{u as __pageData,g as default};
